export type EquipmentType = {
  id: string
  name: string
  type:
    | 'Armure'
    | 'Arme'
    | 'Bijou'
    | 'Robe'
    | 'Item'
    | 'Carquois'
    | 'Arc'
    | 'Bâton'
    | 'Collier'
    | 'Bracelet'
    | 'Anneau'
    | 'Cape'
    | 'Ceinture'
    | 'Bottes'
    | 'Gants'
    | 'Heaume'
    | 'Bouclier'
    | 'Jambières'
    | 'Orbe'
  for: number // Force (prérequis)
  end: number // Endurance
  dext: number // Dextérité (Agility)
  int: number // Intelligence
  sag: number // Sagesse (Wisdom)
  deg: string // Dégâts « min - max » (calculés depuis le Damage Roll WDA)
  ca: number // Classe d'armure (AC)
  bonus: string[]
  rarity?: 'Commun' | 'Rare' | 'Épique' | 'Légendaire'
  location: string
  locations?: { type: string; name: string; dropRate?: string }[]
  coordinates?: { type: string; name: string; coords: { x: number; y: number; world: number }[] }[]
}

